#include <stdio.h>

// Function to search for an element in the array
int Search(int arr[], int x, int n) {
    for (int i = 0; i < n; i++) {
        if (arr[i] == x) {
            return (i + 1); //Return the 1-based index if element if found
        }
    }
    return -1; // Return -1 if element is not found
}

int main() {
    int t; 
    scanf("%d", &t); 
    while (t--) {
        int n;
        scanf("%d", &n); 
        int x;
        scanf("%d", &x); 

        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", Search(arr, x, n));
    }
    return 0;
}

